---@class StructDreamFountainInfo
LXImport(".StructHero")
local StructDreamFountainInfo = LxClass("StructDreamFountainInfo", nil)

function StructDreamFountainInfo:StructDreamFountainInfo()
    self.type = 0                       --参照 DreamFountainType
    self.refId = 0                      --等级配置表Id
    self.freeCount = 0                  --可拥有免费次数
    self.useFreeCount = 0               --已使用免费次数
    self.quickCount = 0                 --付费快速次数
    self.useQuickCount = 0              --已使用付费快速次数
    self.rewardBox = {}                 --资源池详情     Table
    self.heroLists = {}                 --加成伙伴列表 {hero = 加成伙伴Table,index = 位置索引 从1起}
    self.extraRate = 0                  --额外加成系数
    self.lastReceiveTime = 0            --上次收取时间
end

function StructDreamFountainInfo:CreateByPb(pb)
    self.type = pb.type
    self.refId = pb.refId
    self.freeCount = pb.freeCount
    self.useFreeCount = pb.useFreeCount
    self.quickCount = pb.quickCount
    self.useQuickCount = pb.useQuickCount
    local rewardBox = pb.rewardBox
    local heroLists = pb.heroLists
    self.rewardBox = {}
    for i, v in ipairs(rewardBox) do
        local item = StructRewardItem:New()
        item:CreateByPb(v)
        table.insert(self.rewardBox,item)
    end
    self.heroLists = {}
    for i, v in ipairs(heroLists) do
        local heroInfo = v.hero
        local hero = StructHero:New()
        hero:CreateByPb(heroInfo)
        local data = {
            hero = hero:GetServerData(),
            index = v.index,
            playerName = v.playerName
        }
        table.insert(self.heroLists,data)
    end
    local extraRate = pb.extraRate
    if extraRate then
        local addExtraRate = string.format("%.3f",extraRate)
        self.extraRate = tonumber(addExtraRate)
    end
    self.lastReceiveTime = pb.lastReceiveTime
end

return StructDreamFountainInfo